INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (1346, 'دەولەمەندێ دەینێ خۆ نەدەت زۆرداره', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «مَطْلُ الْغَنِيِّ ظُلْمٌ، فَإِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيٍّ فَلْيَتْبَعْ».', 'ئــه‌بــوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: نه‌دانا ده‌وله‌مه‌ندى بۆ ده‌ینێ خۆ زۆردارییه‌، و ئه‌گه‌ر ئێك بۆ كه‌سه‌كێ تێر و تژى هاته‌ حه‌واله‌كرن، بلا ئه‌و ب وێ حه‌والێ بكه‌ت.', NULL, true),
  (1356, 'ئەوێ ژ دیارییا خۆ لێڤه ببت', 'عَنْ ابْنِ عَبَّاسٍ رضي الله عنه قَالَ: قَالَ النَّبِيُّﷺ : «الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَقِيءُ ثُمَّ يَعُودُ فِي قَيْئِهِ».', 'ئبن عه‌بباس -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌وێ ل خه‌لات و دیارییا خۆ لێڤه‌ دبت، وه‌كى صه‌یه‌ دلێ خۆ ڕادكه‌ت و لێ دزڤڕته‌ڤه‌.', NULL, true),
  (1366, 'خێرا چاندنێ', 'عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «مَا مِنْ مُسْلِمٍ يَغْرِسُ غَرْسًا، أَوْ يَزْرَعُ زَرْعًا، فَيَأْكُلُ مِنْهُ طَيْرٌ، أَوْ إِنْسَانٌ، أَوْ بَهِيمَةٌ إِلَّا كَانَ لَهُ بِهِ صَدَقَةٌ».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گــۆت: هـــه‌ر مــوسـلـمـانــه‌كێ شتله‌كێ د عه‌ردى ڕا بكه‌ت، یان داره‌كێ (ژ تۆڤى) بچینت، ڤێجا طه‌یره‌ك یان مرۆڤه‌ك، یان حه‌یوانه‌ك ژێ بخۆت، ئه‌و دێ بۆ وى بته‌ خێر.', NULL, true),
  (1376, 'هەڤڕكییەكا د ئەمانەتى دا', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ النَّبِيُّﷺ : «اشْتَرَى رَجُلٌ مِنْ رَجُلٍ عَقَارًا لَهُ، فَوَجَدَ الرَّجُلُ الَّذِي اشْتَرَى الْعَقَارَ فِي عَقَارِهِ جَرَّةً فِيهَا ذَهَبٌ، فَقَالَ لَهُ الَّذِي اشْتَرَى الْعَقَارَ: خُذْ ذَهَبَكَ مِنِّي إِنَّمَا اشْتَرَيْتُ مِنْكَ الْأَرْضَ، وَلَمْ أَبْتَعْ مِنْكَ الذَّهَبَ، وَقَالَ الَّذِي لَهُ الْأَرْضُ: إِنَّمَا بِعْتُكَ الْأَرْضَ وَمَا فِيهَا، فَتَحَاكَمَا إِلَى رَجُلٍ فَقَالَ الَّذِي تَحَاكَمَا إِلَيْهِ: أَلَكُمَا وَلَدٌ؟ قَالَ أَحَدُهُمَا: لِي غُلَامٌ، وَقَالَ الْآخَرُ: لِي جَارِيَةٌ، قَالَ: أَنْكِحُوا الْغُلَامَ الجَارِيَةَ، وَأَنْفِقُوا عَلَى أَنْفُسِهِمَا مِنْهُ، وَتصَدَّقَا».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: زه‌لامه‌كى پارچه‌یه‌كا عه‌رده‌كى ژ ئێكى كڕى، و جه‌ڕكه‌كێ زێڕى د عه‌ردى ڕا دیت، بكڕێ عه‌ردى گۆته‌ خودانێ عه‌ردى: زێڕێ خۆ ببه‌، من عه‌ردى یێ ژ ته‌ كڕى نه‌ زێڕ، خودانێ عه‌ردى گۆتێ: من عه‌رد ب وى تشتى ڤه‌ یێ فرۆتییه‌ ته‌ یێ د ناڤ دا، ڤێجا وان حوكمێ خۆ بره‌ نك زه‌لامه‌كى، وى زه‌لامى گۆته‌ وان: هه‌وه‌ عه‌یال هه‌یه‌؟ ئێكى گۆت: من كوڕه‌كێ هه‌ى، یێ دى گۆت: من كچه‌كا هه‌ى، زه‌لامى گۆتێ: وێ كچێ بده‌نه‌ وى كوڕى، و وى مالى ل وان خه‌رج بكه‌ن، و خێرێ ژێ بده‌ن.', NULL, true),
  (1386, 'زەلامێ ژ هەمییان پتر خودێ حەز ژێ ناكەت', 'عَنْ عَائِشَةَ -رَضِيَ الله عَنْهَا- عَنْ النَّبِيِّﷺ قَالَ: «إِنَّ أَبْغَضَ الرِّجَالِ إِلَى الله الْأَلَدُّ الخَصِمُ».', 'عائیشا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: زه‌لامێ ژ هه‌مییان پتر خودێ حه‌ز ژێ ناكه‌ت، هه‌ڤڕكێ دژواره‌.', NULL, true),
  (1396, 'زیرەك ئەوه یێ بشێته خۆ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «لَيْسَ الشَّدِيدُ بِالصُّرَعَةِ، إِنَّمَا الشَّدِيدُ الَّذِي يَمْلِكُ نَفْسَهُ عِنْدَ الْغَضَبِ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: زیره‌ك ئه‌و نینه‌ یێ ب خۆلێكدانێ یێ زیره‌ك بت، هه‌ما یێ زیره‌ك ئه‌وه‌ یێ ل ده‌مێ كه‌ربێ بشێته‌ خۆ.', NULL, true),
  (1406, 'هندەك گونەهێن مەزن', 'عَنْ ثَابِتِ بْنَ الضَّحَّاكِ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «مَنْ حَلَفَ عَلَى يَميْنٍ بمِلَّةٍ غَيْرِ الإِسْلاَمِ كاذبًا فَهْوَ كَمَا قَالَ، وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ، وَلَيْسَ عَلَى رَجُلٍ نَذْرٌ فِيمَا لاَ يَمْلِكُه» زاد في رواية: «وَلَعْنُ المُؤْمِنِ كَقَتْلِهِ، وَمَنْ رَمَى مُؤْمِنًا بِكُفْرٍ فَهْوَ كَقَتْلِهِ».', 'ثابتێ كوڕێ ضه‌ححاكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ ژ دره‌و سوینده‌كێ بخۆت (و بێژت: ئه‌گه‌ر وه‌سا نه‌بت ئه‌و ل سه‌ر فلان دینى بت ژ بلى ئیسلامێ) ئه‌و دێ وه‌سا بت وه‌كى وى گۆتى، و هه‌چییێ د دنیایێ دا خۆ ب تشته‌كى بكوژت ڕۆژا قیامه‌تێ ئه‌و دێ ب وى تشتى ئێته‌ عه‌زابدان، و چو نه‌زر ل سه‌ر زه‌لامى نینه‌ د وى تشتى دا یێ وى نه‌بت. و د ریوایه‌ته‌كا دى دا زێده‌ دكه‌ت و دبێژت: له‌عن باراندن ل خودان باوه‌رى وه‌كى كوشتنا وییه‌، و هه‌چییێ خودان باوه‌ره‌كى كافر بكه‌ت، ئه‌و وه‌كى كوشتنا وییه‌.', NULL, true),
  (1416, 'چێ نابت كەس مرنێ بخوازت', 'عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: قال النَّبِيُّﷺ : «لَا يَتَمَنَّيَنَّ أَحَدُكُمْ المَوْتَ مِنْ ضُرٍّ أَصَابَهُ، فَإِنْ كَانَ لَا بُدَّ فَاعِلًا فَلْيَقُلْ: اللهمَّ أَحْيِنِي مَا كَانَتْ الحَيَاةُ خَيْرًا لِي، وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئێك ژ هه‌وه‌ ژ به‌ر نه‌خۆشییه‌كا گه‌هشتییێ بلا داخوازا مرنێ نه‌كه‌ت، و ئه‌گه‌ر وى چو ڕێ نه‌بت و دڤێت وه‌ بكه‌ت، بلا ئه‌و بێژت: ئه‌ى خودا تو من بهێله‌ زێندى هندى ژیان بۆ من یا ب خێرتر بت، و تو من بمرینه‌ ئه‌گه‌ر مرن بۆ من ب خێرتر بت.', NULL, true),
  (1426, 'گرنگییا ئەخلاقێ باش', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه قَالَ: لَمْ يَكُنْ النَّبِيُّﷺ فَاحِشًا وَلَا مُتَفَحِّشًا، وَكَانَ يَقُولُ: «إِنَّ مِنْ خِيَارِكُمْ أَحْسَنَكُمْ أَخْلَاقًا».', 'عه‌بدللاهێ كوڕێ عه‌مرى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌ر -سلاڤ لێ بن- مرۆڤه‌كێ فه‌حش نه‌بوو، و وى فه‌حشاتى نه‌ دكر ژى، و وى گۆت: باشێ هه‌وه‌ ئه‌وه‌ یێ ئه‌خلاقێ وى چێتر بت.', NULL, true),
  (1436, 'كەنییا پێغەمبەرى گڕنژین بوو', 'عَنْ عَائِشَةَ -رَضِيَ الله عَنْهَا- قَالَتْ: مَا رَأَيْتُ النَّبِيَّﷺ مُسْتَجْمِعًا قَطُّ ضَاحِكًا حَتَّى أَرَى مِنْهُ لَهَوَاتِهِ، إِنَّمَا كَانَ يَتَبَسَّمُ.', 'عائیشا -خودێ ژێ رازى بت- دبێژت: من پێغه‌مبه‌ر -سلاڤ لێ بن- قه‌ت نه‌دیت كه‌نییه‌كا وه‌سا كربت حه‌تا كو ئه‌ز پاشییا ده‌ڤێ وى ببینم، هه‌ما ب تنێ ئه‌و دگڕنژى.', NULL, true),
  (1446, 'باشییا دانێ و خرابییا دەستگرتنێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «مَا مِنْ يَوْمٍ يُصْبِحُ الْعِبَادُ فِيهِ إِلَّا مَلَكَانِ يَنْزِلَانِ فَيَقُولُ أَحَدُهُمَا: اللهمَّ أَعْطِ مُنْفِقًا خَلَفًا، وَيَقُولُ الْآخَرُ: اللهمَّ أَعْطِ مُمْسِكًا تَلَفًا».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ر ڕۆژه‌كا ل به‌نییان دبته‌ سپێده‌ دو ملیاكه‌ت دئێنه‌ خوارێ، ئێك ژ وان دبێژت: ئه‌ى خودا هه‌چییێ بده‌ت تو بۆ به‌ده‌ل ڤه‌كه‌ى، و یێ دى دبێژت: هه‌چییێ نه‌ده‌ت كو لێ بته‌لێفى.', NULL, true),
  (1456, 'خێرا خەزنەدارێ ئەمین', 'عَنْ أَبِي مُوسَى رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «إِنَّ الخَازِنَ المُسْلِمَ الْأَمِينَ الَّذِي يُنْفِذُ -وَرُبَّمَا قَالَ يُعْطِي- مَا أُمِرَ بِهِ، فَيُعْطِيهِ كَامِلًا مُوَفَّرًا، طَيِّبَةً بِهِ نَفْسُهُ، فَيَدْفَعُهُ إِلَى الَّذِي أُمِرَ لَهُ بِهِ، أَحَدُ الْمُتَصَدِّقَيْنِ».', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خــه‌زنــه‌دارێ مــوسـلمانێ ئه‌مین ئه‌وێ وى تشتى ب تمامى ب جهـ دئینت -یان گۆت: دده‌ت- یێ فه‌رمان پێ لێ هاتییه‌كرن، و ب دله‌كێ خۆش بده‌ته‌ وى یێ فه‌رمان پێ لێ هاتییه‌كرن، ئه‌و ئێك ژ خێركه‌رانه‌.', NULL, true),
  (1466, 'دەمێ ژن خوارنێ ژ مالا خۆ ددەت', 'عَنْ عَائِشَةَ -رضي الله عنها- قَالَتْ: قَالَ رَسُولُ اللهﷺ : «إِذَا أَنْفَقَتِ المَرْأَةُ مِنْ طَعَامِ بَيْتِهَا غَيْرَ مُفْسِدَةٍ، كَانَ لَهَا أَجْرُهَا بِمَا أَنْفَقَتْ، وَلِزَوْجِهَا أَجْرُهُ بِمَا كَسَبَ، وَلِلْخَازِنِ مِثْلُ ذَلِكَ، لَا يَنْقُصُ بَعْضُهُمْ أَجْرَ بَعْضٍ شَيْئًا».', 'عائیشا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ژن ژ خوارنا مالا خۆ بێى یا خرابكار بت خه‌رج بكه‌ت، خێرا وى تشتێ وێ خه‌رجكرى بۆ وێ هه‌یه‌، و خێر بۆ مێرێ وێ ژ به‌ر كه‌سبا وى هه‌یه‌، و بۆ خه‌زنه‌دارى ژى وه‌سا هه‌یه‌، هنده‌ك ژ وان خێرا هنده‌كان كێم ناكه‌ن.', NULL, true),
  (1476, 'خێرا وى یێ بیژنێ و هەژارى ب خودان دكەت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ، كَالمُجَاهِدِ فِي سَبِيلِ الله، أوالْقَائِمِ اللیلَ، الصَّائِمِ النَهَارَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌وێ ب كارێ بیژن و هه‌ژارى ڕادبت، وه‌كى وییه‌ یێ جیهادێ د ڕێكا خودێ دا دكه‌ت، یان یێ ب شه‌ڤێ عیباده‌تى دكه‌ت، و ب ڕۆژێ یێ ب ڕۆژى.', NULL, true),
  (1486, 'موسلمان دڤێت هەر خێرێ بكەت', 'عَنْ أَبِي موسى الأشعري رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «عَلَى كُلِّ مُسْلِمٍ صَدَقَةٌ» قِيلَ: أَرَأَيْتَ إِنْ لَمْ يَجِدْ؟ قَالَ: «يَعْتَمِلُ بِيَدَيْهِ فَيَنْفَعُ نَفْسَهُ وَيَتَصَدَّقُ» قَالَ: قِيلَ: أَرَأَيْتَ إِنْ لَمْ يَسْتَطِعْ؟ قَالَ: «يُعِينُ ذَا الحَاجَةِ المَلْهُوفَ» قَالَ: قِيلَ لَهُ: أَرَأَيْتَ إِنْ لَمْ يَسْتَطِعْ؟ قَالَ: «يَأْمُرُ بِالمَعْرُوفِ أَوِ الخَيْرِ» قَالَ: أَرَأَيْتَ إِنْ لَمْ يَفْعَلْ؟ قَالَ: «يُمْسِكُ عَنِ الشَّرِّ، فَإِنَّهَا صَدَقَةٌ».', 'ئــه‌بــوو مـــووســایــێ ئــه‌شـعـه‌رى‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ل سه‌ر هه‌ر موسلمانه‌كى خێره‌ك هه‌یه‌. هاته‌ گۆتن: پا ئه‌گه‌ر وى چو نه‌بت؟ گۆت: دێ كارى ب ده‌ستێ خۆ كه‌ت، ڤێجا دێ مفایى گه‌هینته‌ خۆ و خێرێ كه‌ت. هاته‌ گۆتن: پا ئه‌گه‌ر نه‌شێت وه‌ بكه‌ت؟ گۆت: دێ هاریكارییا كه‌سێ پێتڤى و بێ ڕێ كه‌ت. هاته‌ گۆتن: پا ئه‌گه‌ر نه‌شیا وه‌ بكه‌ت؟ گۆت: دێ فه‌رمانێ ب باشییێ یان خێرێ كه‌ت. گۆت: پا ئه‌گه‌ر وى وه‌ نه‌كر؟ گۆت: خرابییێ ناكه‌ت، ئه‌و خێره‌.', NULL, true),
  (1496, 'باشترین خێر', 'عن حَكِيمِ بْنِ حِزَامٍ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «أَفْضَلُ الصَّدَقَةِ، أَوْ خَيْرُ الصَّدَقَةِ عَنْ ظَهْرِ غِنًى، وَالْيَدُ الْعُلْيَا خَيْرٌ مِنَ الْيَدِ السُّفْلَى، وَابْدَأْ بِمَنْ تَعُولُ».', 'حه‌كیمێ كوڕێ حزامى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چێترین خێر، یان باشترین خێر ئه‌وه‌ یا ژ ده‌وله‌مه‌ندییێ بت، و ده‌ســتــێ بـلـنـدتــر باشتره‌ ژ ده‌ستێ نزمتر، و تو ژ وى ده‌ست پێ بكه‌ یێ تو وى ب خودان دكه‌ى.', NULL, true),
  (1506, 'دەولەمەندییا دورست', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «لَيْسَ الْغِنَى عَنْ كَثْرَةِ الْعَرَضِ، وَلَكِنَّ الْغِنَى غِنَى النَّفْسِ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ده‌وله‌مه‌ندى نه‌ ب هه‌بوونا گه‌له‌ك په‌رتالییه‌، به‌لێ ده‌وله‌مه‌ندى ده‌وله‌مه‌ندییا نه‌فسێیه‌.', NULL, true),
  (1516, 'هەژارێ دورست كییە؟', 'عن أَبي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ النَّبِيُّﷺ : «لَيْسَ الْمِسْكِينُ الَّذِي يَطُوفُ عَلَى النَّاسِ تَرُدُّهُ اللُّقْمَةُ وَاللُّقْمَتَانِ، وَالتَّمْرَةُ وَالتَّمْرَتَانِ، وَلَكِنِ الْمِسْكِينُ الَّذِي لا يَجِدُ غِنًى يُغْنِيهِ، وَلا يُفْطَنُ بِهِ، فَيُتَصَدَّقُ عَلَيْهِ، وَلا يَقُومُ فَيَسْأَلُ النَّاسَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ژار ئه‌و نینه‌ یێ ل سه‌ر خه‌لكى دگه‌ڕیێت ڤێجا پارییه‌ك یان دو، و قه‌سپه‌ك یان دو وى دزڤڕینت، به‌لێ هه‌ژار ئه‌وه‌ یێ ده‌وله‌مه‌ندییه‌ك ب ده‌ست وى نه‌كه‌ڤت وى بێ منه‌ت بكه‌ت، و كه‌سێ هاى ژێ نینه‌ خێرێ د گه‌ل بكه‌ت، و ئه‌و خواستنێ ژ مرۆڤان ناكه‌ت.', NULL, true),
  (1526, 'خواستن كارەكێ باش نینه', 'عن أَبي هُرَيْرَةَ رضي الله عنه عن النَّبِيّﷺ قَالَ: «لأنْ يَحْتَطِبَ أَحَدُكُمْ حُــزْمَـةً عَلَى ظَهْرِهِ، خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ أَحَدًا، فَيُعْطِيَهُ أَوْ يَمْنَعَهُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ئێك ژ هه‌وه‌ باره‌كێ داران ل سه‌ر پشتا خۆ هلگرت، بۆ وى چێتره‌ كو خواستنێ ژ ئێكى بكه‌ت، ڤێجا كانێ ئه‌و دێ ده‌تێ یان نه‌.', NULL, true),
  (1536, 'ئەنجامێ خواستنێ یێ خراب', 'عَنْ عَبْدِ الله بْنِ عمر رضي الله عنه أَنَّ النَّبِيَّﷺ، قَالَ: «لاَ تَزَالُ المَسْأَلَةُ بِأَحَدِكُمْ حَتَّى يَلْقَى الله، وَلَيْسَ فِي وَجْهِهِ مُزْعَةُ لحْمٍ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خواستن دێ مینته‌ ب ئێك ژ هه‌وه‌ ڤه‌ حه‌تا ئه‌و دچته‌ نك خودێ و پشكه‌كا گۆشتى ب ڕوییێ وى ڤه‌ نه‌.', NULL, true);